challenges.solution_code:
def most_frequent_char(s):
    counts = {}
    order = []
    for ch in s:
        if ch not in counts:
            counts[ch] = 0
            order.append(ch)
        counts[ch] += 1
    best = order[0]
    for ch in order:
        if counts[ch] > counts[best]:
            best = ch
    return best

