def account_balance(operations):
    class Account:
        def __init__(self):
            self._balance = 0
        def deposit(self, amount):
            self._balance += amount
        def withdraw(self, amount):
            if self._balance >= amount:
                self._balance -= amount
    acc = Account()
    for kind, amount in operations:
        if kind == "deposit":
            acc.deposit(amount)
        elif kind == "withdraw":
            acc.withdraw(amount)
    return acc._balance

import math

def add_fractions(a, b, c, d):
    class Fraction:
        def __init__(self, num, den):
            self.num = num
            self.den = den
        def reduce(self):
            if self.num == 0:
                return (0, 1)
            g = math.gcd(self.num, self.den)
            return (self.num // g, self.den // g)
    result = Fraction(a * d + c * b, b * d)
    return result.reduce()

def total_pay(employees):
    class Employee:
        def pay(self):
            return 0.0
    class Hourly(Employee):
        def __init__(self, rate, hours):
            self.rate, self.hours = rate, hours
        def pay(self):
            if self.hours > 40:
                return 40 * self.rate + (self.hours - 40) * self.rate * 1.5
            return self.hours * self.rate
    class Salaried(Employee):
        def __init__(self, salary):
            self.salary = salary
        def pay(self):
            return self.salary / 12
    class Commission(Employee):
        def __init__(self, base, sales, rate):
            self.base, self.sales, self.rate = base, sales, rate
        def pay(self):
            return self.base + self.sales * self.rate
    total = 0.0
    for e in employees:
        if e["type"] == "hourly":
            total += Hourly(e["rate"], e["hours"]).pay()
        elif e["type"] == "salaried":
            total += Salaried(e["salary"]).pay()
        elif e["type"] == "commission":
            total += Commission(e["base"], e["sales"], e["rate"]).pay()
    return float(total)

