def compare_versions(v1, v2):
    a = [int(x) for x in v1.split('.')]
    b = [int(x) for x in v2.split('.')]
    while len(a) < len(b):
        a.append(0)
    while len(b) < len(a):
        b.append(0)
    for x, y in zip(a, b):
        if x < y:
            return -1
        if x > y:
            return 1
    return 0

