challenges.solution_code:
def merge_requirements(reqs):
    def higher(v1, v2):
        a = [int(x) for x in v1.split('.')]
        b = [int(x) for x in v2.split('.')]
        while len(a) < len(b):
            a.append(0)
        while len(b) < len(a):
            b.append(0)
        for x, y in zip(a, b):
            if x != y:
                return x > y
        return False
    result = {}
    for r in reqs:
        name, version = r.split('==')
        name = name.strip()
        version = version.strip()
        if name not in result or higher(version, result[name]):
            result[name] = version
    return result

