import time

def has_dup_slow(xs):          # O(n^2): compares every pair
    for i in range(len(xs)):
        for j in range(i + 1, len(xs)):
            if xs[i] == xs[j]:
                return True
    return False

def has_dup_fast(xs):          # O(n): one pass with a set
    seen = set()
    for x in xs:
        if x in seen:
            return True
        seen.add(x)
    return False

data = list(range(20000))      # no duplicates -> worst case
for fn in (has_dup_slow, has_dup_fast):
    t = time.perf_counter()
    fn(data)
    print(fn.__name__, round(time.perf_counter() - t, 4), "s")
# The O(n^2) version is dramatically slower as data grows.

