graph = {'A': ['B', 'C'], 'B': ['D'], 'C': ['D'], 'D': []}

def bfs(start):
    visited = []
    q = deque([start])
    seen = {start}
    while q:
        node = q.popleft()      # front of the queue
        visited.append(node)
        for nb in graph[node]:
            if nb not in seen:
                seen.add(nb)
                q.append(nb)    # enqueue neighbors
    return visited

print(bfs('A'))   # ['A', 'B', 'C', 'D']

