challenges.solution_code:
from collections import deque

def process_queue(ops):
    q = deque()
    for op in ops:
        if op[0] == "enqueue":
            q.append(op[1])
        elif op[0] == "dequeue":
            if q:
                q.popleft()
    return list(q)

