class Node:
    def __init__(self, val, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

root = Node(1, Node(2, Node(4), Node(5)), Node(3))

def count_leaves(node):
    if node is None:
        return 0
    if node.left is None and node.right is None:
        return 1
    return count_leaves(node.left) + count_leaves(node.right)

print(count_leaves(root))  # 3  (nodes 4, 5, 3)

def preorder_iter(node):
    out, stack = [], [node] if node else []
    while stack:
        n = stack.pop()
        out.append(n[0])
        # push right first so left is processed next
        if n[2]: stack.append(n[2])
        if n[1]: stack.append(n[1])
    return out

tree = (1, (2, (4, None, None), None), (3, None, None))
print(preorder_iter(tree))  # [1, 2, 4, 3]

