from collections import deque

def level_order(tree):
    if tree is None:
        return []
    result, q = [], deque([tree])
    while q:
        level = []
        for _ in range(len(q)):
            node = q.popleft()
            level.append(node[0])
            if node[1]:
                q.append(node[1])
            if node[2]:
                q.append(node[2])
        result.append(level)
    return result

