graph = {
    "A": ["B", "C"],
    "B": ["D"],
    "C": ["D"],
    "D": [],
}

def dfs(graph, node, seen=None, order=None):
    if seen is None:
        seen, order = set(), []
    seen.add(node)
    order.append(node)
    for nb in graph[node]:
        if nb not in seen:
            dfs(graph, nb, seen, order)
    return order

print(dfs(graph, "A"))  # ['A', 'B', 'D', 'C']

def build_undirected(edges):
    graph = {}
    for u, v in edges:
        graph.setdefault(u, []).append(v)
        graph.setdefault(v, []).append(u)
    return graph

edges = [("A", "B"), ("A", "C"), ("B", "D")]
g = build_undirected(edges)
print(g)  # {'A': ['B', 'C'], 'B': ['A', 'D'], 'C': ['A'], 'D': ['B']}

