challenges.solution_code:
from collections import deque

def has_path(graph, start, end):
    if start == end:
        return True
    seen = {start}
    queue = deque([start])
    while queue:
        node = queue.popleft()
        for nb in graph[node]:
            if nb == end:
                return True
            if nb not in seen:
                seen.add(nb)
                queue.append(nb)
    return False

