from functools import lru_cache

def fib_slow(n):          # exponential: recomputes subproblems
    if n < 2:
        return n
    return fib_slow(n - 1) + fib_slow(n - 2)

@lru_cache(maxsize=None)   # cache makes it linear time
def fib_fast(n):
    if n < 2:
        return n
    return fib_fast(n - 1) + fib_fast(n - 2)

print(fib_slow(10))  # 55
print(fib_fast(50))  # 12586269025  (instant thanks to caching)

