import math

def dot(a, b):
    return sum(x * y for x, y in zip(a, b))

def cosine_similarity(a, b):
    denom = math.sqrt(dot(a, a)) * math.sqrt(dot(b, b))
    if denom == 0:
        raise ValueError("zero-magnitude vector")
    return dot(a, b) / denom

def angle_degrees(a, b):
    c = max(-1.0, min(1.0, cosine_similarity(a, b)))
    return math.degrees(math.acos(c))

print(dot([1, 2, 3], [4, 5, 6]))            # 32
print(round(cosine_similarity([1, 0], [0, 1]), 4))  # 0.0 (orthogonal)
print(round(angle_degrees([1, 0], [1, 1]), 4))      # 45.0

