def matrix_power(M, n):
    size = len(M)
    def matmul(A, B):
        return [[sum(A[i][t] * B[t][j] for t in range(len(B)))
                 for j in range(len(B[0]))] for i in range(len(A))]
    R = [[1 if i == j else 0 for j in range(size)] for i in range(size)]
    for _ in range(n):
        R = matmul(R, M)
    return R

