def dominant_eigenvalue(M, iters):
    n = len(M)
    v = [1.0] * n
    lam = 0.0
    for _ in range(iters):
        w = [sum(M[i][j] * v[j] for j in range(n)) for i in range(n)]
        lam = max(w, key=abs)
        v = [x / lam for x in w]
    return round(lam, 4)

