def running_median(nums):
    result = []
    seen = []
    for x in nums:
        seen.append(x)
        s = sorted(seen)
        n = len(s)
        mid = n // 2
        if n % 2 == 1:
            result.append(s[mid])
        else:
            result.append((s[mid - 1] + s[mid]) / 2)
    return result

