def f(x, y):
    return x**2 * y + y**3   # partials: df/dx = 2xy, df/dy = x^2 + 3y^2

def num_partial(f, var, x, y, h=1e-5):
    if var == 'x':
        return (f(x + h, y) - f(x - h, y)) / (2 * h)
    return (f(x, y + h) - f(x, y - h)) / (2 * h)

x, y = 1.0, 2.0
print('df/dx analytic:', 2 * x * y)             # 4.0
print('df/dx numeric :', num_partial(f, 'x', x, y))
print('df/dy analytic:', x**2 + 3 * y**2)        # 13.0
print('df/dy numeric :', num_partial(f, 'y', x, y))

# Minimize f(x, y) = (x - 3)^2 + (y + 1)^2 ; min at (3, -1)
def grad(x, y):
    return (2 * (x - 3), 2 * (y + 1))   # (df/dx, df/dy)

x, y, lr = 0.0, 0.0, 0.1
for step in range(20):
    gx, gy = grad(x, y)
    x -= lr * gx     # move opposite the gradient
    y -= lr * gy
print(round(x, 4), round(y, 4))   # -> approaches 3.0, -1.0

