def histogram(data, bins):
    lo = min(data)
    hi = max(data)
    width = (hi - lo) / bins
    counts = [0] * bins
    for x in data:
        if x == hi:
            idx = bins - 1
        else:
            idx = int((x - lo) / width)
        counts[idx] += 1
    return counts

