def execution_order_valid(counts):
    prev = None
    for c in counts:
        if c is None:
            continue
        if prev is not None and c <= prev:
            return False
        prev = c
    return True

def restart_run_all_state(cells):
    defined = set()
    missing = []
    for assigned, uses in cells:
        for u in uses:
            if u not in defined and u not in missing:
                missing.append(u)
        if assigned is not None:
            defined.add(assigned)
    return missing

