import math
from collections import Counter

def info_gain(parent, groups):
    def ent(labels):
        n = len(labels)
        if n == 0:
            return 0.0
        c = Counter(labels)
        return -sum((x / n) * math.log2(x / n) for x in c.values())
    total = len(parent)
    weighted = sum((len(g) / total) * ent(g) for g in groups)
    return round(ent(parent) - weighted, 4)

