def knn_classify(train, labels, query, k):
    dists = []
    for point, label in zip(train, labels):
        d = sum((a - b) ** 2 for a, b in zip(point, query)) ** 0.5
        dists.append((d, label))
    dists.sort(key=lambda t: t[0])
