def cross_val_split(n, k, fold):
    fold_sizes = [n // k + (1 if i < n % k else 0) for i in range(k)]
    folds, start = [], 0
    for size in fold_sizes:
        folds.append(list(range(start, start + size)))
        start += size
    test = folds[fold]
    train = [i for i in range(n) if i not in test]
    return (train, test)

