def mlp(x, W1, b1, W2, b2):
    hidden = []
    for w, b in zip(W1, b1):
        total = b
        for wi, xi in zip(w, x):
            total += wi * xi
        hidden.append(max(0, total))
    out = []
    for w, b in zip(W2, b2):
        total = b
        for wi, hi in zip(w, hidden):
            total += wi * hi
        out.append(total)
    return out

