import math

def bce(y_true, y_pred, eps=1e-12):
    total = 0.0
    for t, p in zip(y_true, y_pred):
        p = min(max(p, eps), 1 - eps)
        total += -(t * math.log(p) + (1 - t) * math.log(1 - p))
    return total / len(y_true)

def huber(y_true, y_pred, delta):
    total = 0.0
    for t, p in zip(y_true, y_pred):
        e = abs(t - p)
        if e <= delta:
            total += 0.5 * e * e
        else:
            total += delta * (e - 0.5 * delta)
    return total / len(y_true)

