import math

def k_nearest(query, vectors, k):
    def cos(a, b):
        dot = sum(x * y for x, y in zip(a, b))
        na = math.sqrt(sum(x * x for x in a))
        nb = math.sqrt(sum(y * y for y in b))
        return dot / (na * nb)
    scored = [(-cos(query, v), i) for i, v in enumerate(vectors)]
    scored.sort()
    return [i for _, i in scored[:k]]

