def agent_loop(commands, budget):
    value, steps = 0, 0
    for cmd in commands:
        if steps >= budget:
            break
        parts = cmd.split()
        op = parts[0]
        steps += 1
        if op == "stop":
            break
        n = int(parts[1])
        if op == "add":
            value += n
        elif op == "mul":
            value *= n
    return (value, steps)

