        errors.append("invalid jsonrpc version")
    if not isinstance(msg.get("method"), str):
        errors.append("method must be a string")
    if "params" in msg and not isinstance(msg["params"], (list, dict)):
        errors.append("params must be array or object")
    if "id" in msg and not isinstance(msg["id"], (int, str)):
        errors.append("id must be int or string")
    return errors

