def token_bucket(capacity, refill_rate, requests):
    tokens = capacity
    last_t = requests[0][0] if requests else 0
    out = []
    for t, need in requests:
        tokens = min(capacity, tokens + (t - last_t) * refill_rate)
        last_t = t
        if tokens >= need:
            tokens -= need
            out.append(True)
        else:
            out.append(False)
    return out

