from collections import OrderedDict

def lru_keys(capacity, operations):
    cache = OrderedDict()
    for op in operations:
        if op[0] == 'put':
            key, val = op[1], op[2]
            if key in cache:
                cache.move_to_end(key)
            cache[key] = val
            if len(cache) > capacity:
                cache.popitem(last=False)
        elif op[0] == 'get':
            key = op[1]
            if key in cache:
                cache.move_to_end(key)
    return list(cache.keys())

