import hmac, hashlib, base64, json, time

SECRET = b"server-only-signing-key"

def issue_token(user_id: str, ttl_seconds: int = 900) -> str:
    payload = {"sub": user_id, "exp": int(time.time()) + ttl_seconds}
    body = base64.urlsafe_b64encode(json.dumps(payload).encode())
    sig = hmac.new(SECRET, body, hashlib.sha256).hexdigest()
    return f"{body.decode()}.{sig}"

def verify_token(token: str) -> dict | None:
    body, sig = token.split(".")
    expected = hmac.new(SECRET, body.encode(), hashlib.sha256).hexdigest()
    if not hmac.compare_digest(sig, expected):
        return None  # tampered
    payload = json.loads(base64.urlsafe_b64decode(body))
    if payload["exp"] < time.time():
        return None  # expired
    return payload

