def total_disk_usage(images):
    seen = set()
    total = 0
    for layers in images.values():
        for layer_id, size in layers:
            if layer_id not in seen:
                seen.add(layer_id)
                total += size
    return total

def nodes_needed(pod_cpus, capacity):
    nodes = []  # remaining capacity per node
    for cpu in pod_cpus:
        placed = False
        for i in range(len(nodes)):
            if nodes[i] >= cpu:
                nodes[i] -= cpu
                placed = True
                break
        if not placed:
            nodes.append(capacity - cpu)
    return len(nodes)

def count_restarts(results, threshold):
    consec = 0
    restarts = 0
    for r in results:
        if r == 0:
            consec += 1
            if consec == threshold:
                restarts += 1
                consec = 0
        else:
            consec = 0
    return restarts

def best_run(runs, mode='max'):
    best_id = None
    best_val = None
    for run_id, val in runs:
        if best_val is None:
            best_id, best_val = run_id, val
        elif mode == 'max' and val > best_val:
            best_id, best_val = run_id, val
        elif mode == 'min' and val < best_val:
            best_id, best_val = run_id, val
    return best_id

def grid_size(grid):
