    return total

def smooth(values, weight):
    if not values:
        return []
    result = []
    last = values[0]
    for v in values:
        last = last * weight + v * (1 - weight)
        result.append(round(last, 4))
    return result

def best_config(runs, metric, mode="min"):
    best = None
    for r in runs:
        if best is None:
            best = r
        elif mode == "min" and r[metric] < best[metric]:
            best = r
        elif mode == "max" and r[metric] > best[metric]:
            best = r
    return best

