REGISTRY = {"search_docs": search_docs}

# Simulate a sequence of model turns. In reality these come from the API.
model_turns = [
    {"type": "tool_use", "id": "a1", "name": "search_docs",
     "input": {"query": "how long for a refund?"}},
    {"type": "text", "text": "Refunds take 5-7 days."},
]

for turn in model_turns:
    if turn["type"] == "tool_use":
        fn = REGISTRY[turn["name"]]
        result = fn(**turn["input"])
        tool_result = {"tool_use_id": turn["id"], "content": result}
