def validate(schema, args):
    errors = []
    props = schema.get("properties", {})
    for name in schema.get("required", []):
        if name not in args:
            errors.append(f"missing required: {name}")
    type_map = {"string": str, "integer": int, "number": (int, float), "boolean": bool}
    for name, value in args.items():
        spec = props.get(name)
        if spec is None:
            errors.append(f"unexpected arg: {name}")
            continue
        want = type_map.get(spec["type"])
        if want and not isinstance(value, want):
            errors.append(f"bad type for {name}: expected {spec['type']}")
    return errors

schema = {"properties": {"location": {"type": "string"}, "days": {"type": "integer"}},
          "required": ["location"]}
print(validate(schema, {"location": "Paris", "days": 3}))   # []
print(validate(schema, {"days": "three"}))                   # two errors

