def lru_evict(capacity, accesses):
    cache = []  # most-recently-used first
    for key in accesses:
        if key in cache:
            cache.remove(key)
        elif len(cache) >= capacity:
            cache.pop()  # evict least-recently-used (last)
        cache.insert(0, key)
    return cache

