def run_agent(goal, planner, executor, max_replans=3):
    plan = planner(goal, state={})          # LLM returns ordered steps
    state, replans = {}, 0
    while plan:
        step = plan.pop(0)
        result = executor(step, state)      # calls a tool
        state[step['id']] = result
        if not result.get('ok'):
            if replans >= max_replans:
                return {'status': 'failed', 'state': state}
            replans += 1
            plan = planner(goal, state)      # regenerate from current state
    return {'status': 'done', 'state': state}

def makespan(durations, deps):
    def finish(t):
        pre = deps.get(t, [])
        return durations[t] + max((finish(p) for p in pre), default=0)
    return max(finish(t) for t in durations)

