def plan_order(tasks):
    from collections import deque
    indeg = {t: len(pres) for t, pres in tasks.items()}
    dependents = {t: [] for t in tasks}
    for t, pres in tasks.items():
        for p in pres:
            dependents.setdefault(p, []).append(t)
    ready = deque(sorted(t for t in tasks if indeg[t] == 0))
    order = []
    while ready:
        n = ready.popleft()
        order.append(n)
        for d in sorted(dependents[n]):
            indeg[d] -= 1
            if indeg[d] == 0:
                ready.append(d)
    return order if len(order) == len(tasks) else []

def critical_path(durations, deps):
    def finish(t):
        pre = deps.get(t, [])
        return durations[t] + max((finish(p) for p in pre), default=0)
    return max(finish(t) for t in durations)

def wait_for(checks, interval, timeout):
    elapsed = 0
    i = 0
    while elapsed <= timeout:
        if i < len(checks) and checks[i]:
            return elapsed
        elapsed += interval
        i += 1
    return -1

