def token_bucket(capacity, refill_rate, requests):
    tokens = capacity
    last = None
    results = []
    for ts, need in requests:
        if last is not None:
            tokens = min(capacity, tokens + (ts - last) * refill_rate)
        last = ts
        if tokens >= need:
            tokens -= need
            results.append(True)
        else:
            results.append(False)
    return results

