def sliding_window(limit, window, timestamps):
    allowed_times = []
    results = []
    for ts in timestamps:
        allowed_times = [t for t in allowed_times if t > ts - window]
        if len(allowed_times) < limit:
            allowed_times.append(ts)
            results.append(True)
        else:
            results.append(False)
    return results

